from html.parser import HTMLParser
import os, re

class TextExtractor\(HTMLParser\):
    def __init__\(self\):
        super\(\).__init__\(\)
        self.texts = []
        self.skip = 0
        self.skip_tags = {'script','style','code','pre','noscript'}
    def handle_starttag\(self, tag, attrs\):
        if tag in self.skip_tags:
            self.skip += 1
    def handle_endtag\(self, tag\):
        if tag in self.skip_tags and self.skip > 0:
            self.skip -= 1
    def handle_data\(self, data\):
        if self.skip > 0: return
        t = data.strip\(\)
        if len\(t\) > 3 and not t.startswith\('data:'\) and 'base64' not in t[:50]:
            if re.search\(r'[a-zA-Z]{3,}', t\):
                self.texts.append\(t\)

folder = 'D:/Git/ClaudeCourse/Introduction to Agent Skills'
files = [f for f in os.listdir\(folder\) if f.endswith\('.html'\) and f != 'index.html']
for fname in sorted\(files\):
