        parser.feed\(f.read\(\)\)
    print\(f'=== {fname} \({len\(parser.texts\)} segments\) ==='\)
    for t in parser.texts:
        if len\(t\) > 20 and len\(t\) < 500:
            print\(f'  {t[:150]}'\)
